24		 *
25		 * @param init Options.
26		 * @param init.window Window.
27		 * @param init.options Options.
28		 * @param init.target Target.
29		 * @param init.observer Observer.
30		 * @param init.callback Callback.
31		 */
32		constructor(init: {
33			window: BrowserWindow;
34			options: IMutationObserverInit;
35			target: Node;
36			observer: MutationObserver;
37			callback: (record: MutationRecord[], observer: MutationObserver) => void;
38		}) {
39			this.options = init.options;
40			this.target = init.target;
41			this.mutationListener = {
42				options: init.options,
43				callback: new WeakRef((record: MutationRecord) => this.report(record))
44			};
45			this.#window = init.window;
46			this.#observer = init.observer;
